<!-- wp:heading {"level":3,"className":"pillar-title","style":{"color":{"text":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dcolor\u002d\u002dc-gold)"}},"fontSize":"2xl","fontFamily":"cormorant-garamond"} -->
<h3 class="wp-block-heading pillar-title has-text-color has-cormorant-garamond-font-family has-2-xl-font-size" style="color:var(--wp--preset--color--c-gold)"><strong>THE PURPLE GEM</strong></h3>
<!-- /wp:heading -->

<!-- wp:paragraph {"className":"pillar-text","textColor":"c-bone","fontSize":"base","fontFamily":"lato"} -->
<p class="pillar-text has-c-bone-color has-text-color has-lato-font-family has-base-font-size">At the heart of Eldermoor pulses a crystal older than the city itself. It was created to preserve truth — and truth is exactly what it holds. The gem remembers every secret, every betrayal, every soul bound within it. Now its light is fading, and the children born of its glow are the only ones who can learn why.</p>
<!-- /wp:paragraph --></article>
<!-- /wp:group -->

<!-- wp:group {"tagName":"article","metadata":{"name":"Pillar - The Five Dominions"},"className":"world-pillar animate-on-scroll","layout":{"type":"default"}} -->
