<!-- /wp:image -->

<!-- wp:heading {"level":3,"className":"pillar-title","style":{"color":{"text":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dcolor\u002d\u002dc-gold)"}},"fontSize":"2xl","fontFamily":"cormorant-garamond"} -->
<h3 class="wp-block-heading pillar-title has-text-color has-cormorant-garamond-font-family has-2-xl-font-size" style="color:var(--wp--preset--color--c-gold)"><strong>THE FOUNDERS' LIE</strong></h3>
<!-- /wp:heading -->

<!-- wp:paragraph {"className":"pillar-text","textColor":"c-bone","fontSize":"base","fontFamily":"lato"} -->
<p class="pillar-text has-c-bone-color has-text-color has-lato-font-family has-base-font-size">Four founders. Three martyrs. One monster. The stories say they gave their lives for Eldermoor. The truth is that one of them took the others — binding their souls to fuel centuries of stolen immortality. The hero the city still celebrates is the very thing that may destroy it.</p>
<!-- /wp:paragraph --></article>
<!-- /wp:group -->

<!-- wp:group {"tagName":"article","metadata":{"name":"Pillar - The Shadow Tide"},"className":"world-pillar animate-on-scroll","layout":{"type":"default"}} -->
