<!-- /wp:image -->

<!-- wp:heading {"level":3,"className":"pillar-title","style":{"color":{"text":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dcolor\u002d\u002dc-gold)"}},"fontSize":"2xl","fontFamily":"cormorant-garamond"} -->
<h3 class="wp-block-heading pillar-title has-text-color has-cormorant-garamond-font-family has-2-xl-font-size" style="color:var(--wp--preset--color--c-gold)"><strong><strong><strong>FORGE YOUR FATE</strong></strong></strong></h3>
<!-- /wp:heading -->

<!-- wp:paragraph {"className":"pillar-text","textColor":"c-bone","fontSize":"base","fontFamily":"lato"} -->
<p class="pillar-text has-c-bone-color has-text-color has-lato-font-family has-base-font-size">Forge alliances or walk alone. Show mercy or deliver destruction. The path through Eldermoor branches at every turn — different allies, different truths, different consequences. Four endings await, and the choices you make from the very first scene determine which one you'll earn.</p>
